    public boolean checkBankAccountNum(BankAccount _bankAccount)
    {
        next checkBankAccountNum(''); 

        if (strLen(_bankAccount) != 11)
        {
            return checkFailed(strFmt("@UBS:UBSBankFRAccountNumLength", fieldPName(BankAccountMap, AccountNum)));
        }

        return true;
    }
